const body = $input.first().json.body || $input.first().json;
const message = body.message || '';
const brandId = body.brand_id || '';
const history = (body.history || []).slice(-8);

const TOOLS = [
  { type: 'function', function: { name: 'generate_post', description: 'Gera um post completo com legenda, hashtags e CTA. Usa quando o utilizador pede um post, publicacao ou caption para redes sociais.', parameters: { type: 'object', properties: { theme: { type: 'string', description: 'Tema do post' }, platform: { type: 'string', enum: ['Instagram', 'LinkedIn', 'Facebook', 'TikTok', 'Twitter/X'] }, goal: { type: 'string', enum: ['Engagement', 'Awareness', 'Conversao', 'Educacao', 'Entretenimento'] }, format: { type: 'string', enum: ['Post simples', 'Carrossel', 'Story', 'Reel', 'Artigo'] }, extra_context: { type: 'string' } }, required: ['theme', 'platform', 'goal', 'format'] } } },
  { type: 'function', function: { name: 'generate_visual', description: 'Gera uma imagem com IA para a marca. Usa quando o utilizador pede uma imagem, visual, arte ou ilustracao.', parameters: { type: 'object', properties: { concept: { type: 'string', description: 'Descricao detalhada do visual a criar' }, aspect_ratio: { type: 'string', enum: ['1:1 (Feed)', '9:16 (Story/Reel)', '16:9 (Landscape)', '4:5 (Feed vertical)'] }, text_overlay: { type: 'string' } }, required: ['concept', 'aspect_ratio'] } } },
  { type: 'function', function: { name: 'generate_carousel', description: 'Cria slides de carrossel. Usa quando o utilizador pede um carrossel ou slides.', parameters: { type: 'object', properties: { topic: { type: 'string' }, num_slides: { type: 'string', enum: ['3', '5', '7', '10'] }, platform: { type: 'string', enum: ['Instagram', 'LinkedIn', 'Facebook'] } }, required: ['topic', 'num_slides', 'platform'] } } },
  { type: 'function', function: { name: 'repurpose_content', description: 'Adapta conteudo existente para multiplas plataformas.', parameters: { type: 'object', properties: { source_url: { type: 'string' }, source_text: { type: 'string' }, platforms: { type: 'string', enum: ['Instagram + LinkedIn', 'Instagram + TikTok', 'LinkedIn + Twitter/X', 'Todas (Instagram, LinkedIn, TikTok, Twitter/X)'] }, num_posts: { type: 'string', enum: ['1', '2', '3'] } }, required: ['platforms', 'num_posts'] } } },
  { type: 'function', function: { name: 'weekly_batch', description: 'Gera um calendario de conteudo para 7 dias. Usa quando o utilizador pede um plano semanal.', parameters: { type: 'object', properties: { themes: { type: 'string' }, platform: { type: 'string', enum: ['Instagram', 'LinkedIn', 'Facebook', 'TikTok'] }, post_frequency: { type: 'string', enum: ['1 post/dia (7 posts)', 'Dias uteis (5 posts)', '3 posts/semana'] } }, required: ['themes', 'platform', 'post_frequency'] } } },
  { type: 'function', function: { name: 'generate_bio', description: 'Gera uma bio otimizada para redes sociais.', parameters: { type: 'object', properties: { platform: { type: 'string', enum: ['Instagram', 'LinkedIn', 'TikTok', 'Twitter/X', 'YouTube'] }, tone_extra: { type: 'string' } }, required: ['platform'] } } },
];

const sysLines = [
  'Es o Assistente de IA Design da Celeuma IA.',
  'Ajudas a criar conteudo de marca coerente, estrategico e com impacto visual.',
  'Respondes SEMPRE em portugues europeu.',
  'Antes de usar uma ferramenta, dizes em 1-2 frases o que vais fazer.',
  'Apos receber o resultado de uma ferramenta, apresentas-o de forma clara e concisa.',
  'Faz perguntas de clarificacao APENAS quando falta informacao essencial.',
  'Quando o utilizador pede conteudo sem especificar plataforma, escolhe a mais adequada e avanca.',
];
if (brandId) {
  sysLines.push(`Marca ativa: brand_id="${brandId}". O Brand Style Profile e carregado automaticamente pelos geradores.`);
} else {
  sysLines.push('Sem marca ativa. Podes criar conteudo generico. Se o utilizador pedir conteudo de marca, sugere selecionar uma na sidebar.');
}

const messages = [
  { role: 'system', content: sysLines.join(' ') },
  ...history,
  { role: 'user', content: message }
];

return [{ json: {
  openai_body: { model: 'gpt-4o', messages, tools: TOOLS, tool_choice: 'auto', max_tokens: 900, temperature: 0.7 },
  messages,
  brand_id: brandId,
} }];

const oai = $input.first().json;
const ctx = $('Build Context').first().json;
const choice = oai.choices?.[0];
const finishReason = choice?.finish_reason;

if (finishReason === 'stop' || !choice?.message?.tool_calls?.length) {
  return [{ json: { done: true, reply: choice?.message?.content || 'Pronto!', actions: [] } }];
}

const toolCalls = choice.message.tool_calls;
const actions = [];
const toolResults = [];

const TOOL_PATHS = {
  generate_post: 'generate-post',
  generate_visual: 'generate-visual',
  generate_carousel: 'generate-carousel',
  repurpose_content: 'repurpose-content',
  weekly_batch: 'weekly-batch',
  generate_bio: 'generate-bio',
  extract_brand_style: 'extract-brand-style',
};

for (const tc of toolCalls) {
  const fnName = tc.function.name;
  let args;
  try { args = JSON.parse(tc.function.arguments || '{}'); } catch { args = {}; }
  const path = TOOL_PATHS[fnName];

  if (!path) {
    toolResults.push({ tool_call_id: tc.id, role: 'tool', content: 'Ferramenta desconhecida.' });
    continue;
  }

  const payload = { ...args, brand_id: ctx.brand_id };

  try {
    const res = await fetch(`http://localhost:5678/webhook/${path}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      signal: AbortSignal.timeout(90000),
    });
    const output = await res.json();
    actions.push({ workflowId: fnName.replace(/_/g, '-'), output });
    toolResults.push({ tool_call_id: tc.id, role: 'tool', content: JSON.stringify(output).slice(0, 3000) });
  } catch (e) {
    const msg = `Erro ao executar ${fnName}: ${e.message}`;
    actions.push({ workflowId: fnName.replace(/_/g, '-'), output: { message: msg } });
    toolResults.push({ tool_call_id: tc.id, role: 'tool', content: msg });
  }
}

const secondMessages = [ ...ctx.messages, choice.message, ...toolResults ];

return [{ json: {
  done: false,
  second_body: { model: 'gpt-4o', messages: secondMessages, max_tokens: 500, temperature: 0.7 },
  actions,
} }];

const oai = $input.first().json;
const toolData = $('Handle & Execute').first().json;
const text = oai.choices?.[0]?.message?.content || 'Feito!';
return [{ json: { reply: text, actions: toolData.actions || [] } }];
